          else:\n55\t                # 无明显反弹模式\n56\t                price = base_price * (1 + np.random.uniform(-0.03, 0.03) * day / 40)\n57\t\n58\t            prices.append(max(price, 1))\n59\t\n60\t            # 模拟成交量（反弹时放量）\n61\t            if has_bounce and 18 <= day < 38:\n62\t                volume = np.random.uniform(7000, 14000)  # 放量\n63\t            else:\n64\t                volume = np.random.uniform(3000, 8000)   # 正常量\n65\t\n66\t            volumes.append(volume)\n67\t\n68\t        stocks.append({\n69\t            'code': code,\n70\t            'pe': pe,\n71\t            'prices': prices,\n72\t            'volumes': volumes\n73\t        })\n74\t\n75\t    return stocks\n76\t\n77\t\n78\tdef calculate_bollinger_bands(prices, window=20, num_std=2):\n79\t    \"\"\"\n80\t    计算布林带指标\n81\t\n82\t    参数:\n83\t        prices: 价格序列\n84\t        window: 窗口期（默认20日）\n85\t        num_std: 标准差倍数（默认2倍）\n86\t\n87\t    返回:\n88\t        middle: 中轨（SMA）\n89\t        upper: 上轨\n90\t        lower: 下轨\n91\t    \"\"\"\n92\t    if len(prices) < window:\n93\t        return None, None, None\n94\t\n95\t    prices_array = np.array(prices)\n96\t\n97\t    # 计算移动平均（中轨）\n98\t    middle = np.convolve(prices_array, np.ones(window)/window, mode='valid')\n99\t\n100\t    # 计算标准差\n101\t    std_devs = []\n102\t    for i in range(len(prices_array) - window + 1):\n103\t        window_data = prices_array[i:i+window]\n104\t        std_devs.append(np.std(window_data, ddof=1))\n105\t\n106\t    std_devs = np.array(std_devs)\n107\t\n108\t    # 计算上下轨\n109\t    upper = middle + num_std * std_devs\n110\t    lower = middle - num_std * std_devs\n111\t\n112\t    return middle, upper, lower\n113\t\n114\t\n115\tdef detect_bollinger_bounce(prices, window=20):\n116\t    \"\"\"\n117\t    检测布林带反弹信号\n118\t\n119\t    条件：\n120\t    1. 价格曾触及或跌破下轨（最近20天内）\n121\t    2. 最新收盘价回到中轨以上\n122\t\n123\t    返回:\n124\t        (是否反弹, 反弹日期)\n125\t    \"\"\"\n126\t    if len(prices) < window + 10:\n127\t        return False, None\n128\t\n129\t    # 计算布林带\n130\t    middle, upper, lower = calculate_bollinger_bands(prices, window)\n131\t\n132\t    if middle is None:\n133\t        return False, None\n134\t\n135\t    # 检查最新价格是否在中轨以上\n136\t    latest_price = prices[-1]\n137\t    latest_middle = middle[-1]\n138\t\n139\t    if latest_price <= latest_middle:\n140\t        return False, None\n141\t\n142\t    # 检查最近20天内是否触及过下轨\n143\t    # 注意：布林带从第window天开始有值\n144\t    check_range = min(20, len(middle))\n145\t\n146\t    touched_lower = False\n147\t    bounce_idx = None\n148\t\n149\t    for i in range(len(middle) - check_range, len(middle)):\n150\t        price_idx = i + window - 1  # 对应的价格索引\n151\t        if price_idx < len(prices) and prices[price_idx] <= lower[i]:\n152\t            touched_lower = True\n153\t            # 找到触及下轨后首次回到中轨以上的日期\n154\t            for j in range(i + 1, len(middle)):\n155\t                price_j = j + window - 1\n156\t                if price_j < len(prices) and prices[price_j] > middle[j]:\n157\t                    bounce_idx = j\n158\t                    break\n159\t            if bounce_idx:\n160\t                break\n161\t\n162\t    if touched_lower and bounce_idx:\n163\t        # 转换为实际日期（bounce_idx是布林带数组的索引）\n164\t        days_from_end = len(middle) - bounce_idx - 1\n165\t        base_date = datetime(2024, 8, 15)\n166\t        bounce_date = base_date - timedelta(days=days_from_end)\n167\t        return True, bounce_date.strftime('%Y-%m-%d')\n168\t\n169\t    return False, None\n170\t\n171\t\n172\tdef check_volume_condition(volumes):\n173\t    \"\"\"\n174\t    验证量能条件：近5日成交量均值 > 近20日成交量均值\n175\t\n176\t    返回:\n177\t        是否满足量能条件\n178\t    \"\"\"\n179\t    if len(volumes) < 20:\n180\t        return False\n181\t\n182\t    vol_5d = np.mean(volumes[-5:])\n183\t    vol_20d = np.mean(volumes[-20:])\n184\t\n185\t    return vol_5d > vol_20d\n186\t\n187\t\n188\tdef calculate_5d_return(prices):\n189\t    \"\"\"计算近5日涨幅\"\"\"\n190\t    if len(prices) < 6:\n191\t        return 0.0\n192\t\n193\t    price_5d_ago = prices[-6]\n194\t    latest_price = prices[-1]\n195\t\n196\t    return ((latest_price - price_5d_ago) / price_5d_ago) * 100\n197\t\n198\t\n199\tdef main():\n200\t    \"\"\"主函数：执行三步筛选\"\"\"\n201\t\n202\t    print(\"开始执行PE筛选后布林带反弹选股...\")\n203\t    print(\"=\" * 60)\n204\t\n205\t    # 生成模拟数据\n206\t    stocks = generate_mock_data()\n207\t    print(f\"总共获取 {len(stocks)} 只创业板股票\")\n208\t\n209\t    # 第一步：基本面筛选（PE在15-60之间）\n210\t    print(\"\\n第一步：基本面筛选（PE在15-60之间）\")\n211\t    pe_filtered = []\n212\t    for stock in stocks:\n213\t        if 15 <= stock['pe'] <= 60:\n214\t            pe_filtered.append(stock)\n215\t\n216\t    print(f\"PE筛选后剩余 {len(pe_filtered)} 只股票\")\n217\t\n218\t    # 第二步：技术面筛选（布林带反弹）\n219\t    print(\"\\n第二步：技术面筛选（布林带反弹）\")\n220\t    bollinger_filtered = []\n221\t    for stock in pe_filtered:\n222\t        is_bounce, bounce_date = detect_bollinger_bounce(stock['prices'])\n223\t        if is_bounce:\n224\t            stock['bounce_date'] = bounce_date\n225\t            bollinger_filtered.append(stock)\n226\t\n227\t    print(f\"布林带反弹筛选后剩余 {len(bollinger_filtered)} 只股票\")\n228\t\n229\t    # 第三步：量能验证\n230\t    print(\"\\n第三步：量能验证（近5日均量 > 近20日均量）\")\n231\t    final_stocks = []\n232\t    for stock in bollinger_filtered:\n233\t        if check_volume_condition(stock['volumes']):\n234\t            stock['return_5d'] = calculate_5d_return(stock['prices'])\n235\t            final_stocks.append(stock)\n236\t\n237\t    print(f\"量能验证后剩余 {len(final_stocks)} 只股票\")\n238\t\n239\t    # 按PE升序排列，取前8名\n240\t    final_stocks.sort(key=lambda x: x['pe'])\n241\t    top8 = final_stocks[:8]\n242\t\n243\t    print(f\"\\n最终筛选出 {len(top8)} 只股票（按PE升序排列）\")\n244\t    print(\"=\" * 60)\n245\t\n246\t    # 输出结果\n247\t    result_lines = [\"股票代码,PE,布林带反弹日期,近5日涨幅(%)\"]\n248\t\n249\t    for stock in top8:\n250\t        line = f\"{stock['code']},{stock['pe']:.2f},{stock['bounce_date']},{stock['return_5d']:.2f}\"\n251\t        result_lines.append(line)\n252\t 